// 三载体一致:纯 JS 文本输出,零 DOM/uplink/shadow 足迹
import { createEvent, createEvents } from 'https://cdn.jsdelivr.net/npm/ics@3/+esm';
// start 是 [年,月,日,时,分] 数组(非 Date);duration 或 end 必给其一
const { error, value } = createEvent({
  title: data.title,
  start: data.start,
  duration: data.duration,            // 或 end: data.end
  description: data.description,
  location: data.location,
  recurrenceRule: data.recurrenceRule, // RFC5545 RRULE 字符串
  attendees: data.attendees
});
if (error) throw error;                // 校验失败时 error 非 null 且 value 为 null
const blob = new Blob([value], { type: 'text/calendar;charset=utf-8' }); // 供下载
